&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;भारत की भूमि सीमा की लंबाई 15,200 किलोमीटर&amp;nbsp;है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;पड़ोसी देश (सीमा की लंबाई के अवरोही क्रम में)&lt;/p&gt;

&lt;div&gt;
&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;पड़ोसी देश&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;width: 70px; text-align: center;&quot;&gt;&lt;strong&gt;सीमा की लंबाई (किलोमीटर में)&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;सीमावर्ती राज्य&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 125px; text-align: center;&quot;&gt;&lt;strong&gt;बांग्लादेश&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&amp;nbsp;4096.7&lt;/strong&gt;&lt;/td&gt;
